public static string Camelize(this string input)
{
    var pascalized = input.Pascalize();
    if (pascalized.Length == 0)
    {
        return pascalized;
    }

    return string.Create(pascalized.Length, pascalized, static (span, src) =>
    {
        src.AsSpan().CopyTo(span);
        span[0] = char.ToLowerInvariant(span[0]);
    });
}

public static string Underscore(this string input)
{
    // Two regex passes to insert underscores at word boundaries, then replace
    // separators and lowercase in a single StringBuilder pass to minimize allocations.
    var result = UnderscoreRegex1().Replace(input, "$1_$2");
    result = UnderscoreRegex2().Replace(result, "$1_$2");

    var sb = new StringBuilder(result.Length);
    foreach (var c in result)
    {
        if (c == '-' || char.IsWhiteSpace(c))
        {
            sb.Append('_');
        }
        else
        {
            sb.Append(char.ToLowerInvariant(c));
        }
    }

    return sb.ToString();
}

